async function main() {
  const now = new Date();
  const toIso = now.toISOString();
  const fromIso = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
  const channelResp = await api.getTargetChannel();
  const channelId = typeof channelResp === 'string' ? channelResp : (channelResp && (channelResp as any).channelId) ? (channelResp as any).channelId : JSON.stringify(channelResp);
  const result = await api.summarizeChannel({ channelId, fromIso, toIso });
  const out = {
    channelId: (result as any).channelId ?? channelId,
    fromIso: (result as any).fromIso ?? fromIso,
    toIso: (result as any).toIso ?? toIso,
    summary: (result as any).summary,
    topics: (result as any).topics,
    actionItems: (result as any).actionItems,
  };
  console.log(JSON.stringify(out));
}
main();

